#define BLOCK_SIZE 16

__kernel void lud_diagonal(__global float* a, __local float* local_buf, int size, int offset) {
    int i = get_global_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    // Load diagonal block into local memory
    for (j = 0; j < BLOCK_SIZE; j++) {
        local_buf[i * BLOCK_SIZE + j] = a[(offset + i) * size + (offset + j)];
    }

    // Process diagonal block - upper triangle
    for (j = i; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += local_buf[i * BLOCK_SIZE + k] * local_buf[k * BLOCK_SIZE + j];
        }
        local_buf[i * BLOCK_SIZE + j] -= sum;
    }

    // Write back upper triangle
    for (j = i; j < BLOCK_SIZE; j++) {
        a[(offset + i) * size + (offset + j)] = local_buf[i * BLOCK_SIZE + j];
    }

    float diag = local_buf[i * BLOCK_SIZE + i];

    // Process diagonal block - lower triangle
    for (j = i + 1; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += local_buf[j * BLOCK_SIZE + k] * local_buf[k * BLOCK_SIZE + i];
        }
        local_buf[j * BLOCK_SIZE + i] = (local_buf[j * BLOCK_SIZE + i] - sum) / diag;
    }

    // Write back lower triangle
    for (j = i + 1; j < BLOCK_SIZE; j++) {
        a[(offset + j) * size + (offset + i)] = local_buf[j * BLOCK_SIZE + i];
    }
}

__kernel void lud_perimeter(__global float* a, __local float* local_diag, 
                            __local float* local_row, __local float* local_col,
                            int size, int offset) {
    int idx = get_global_id(0);
    int i, j, k;

    if (idx >= BLOCK_SIZE * 2) return;

    int block_idx = idx / BLOCK_SIZE;
    int elem_idx = idx % BLOCK_SIZE;

    // Load diagonal block
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            local_diag[i * BLOCK_SIZE + j] = a[(offset + i) * size + (offset + j)];
        }
    }

    if (block_idx == 0) {
        // Process row blocks (right of diagonal)
        int row_offset = offset + BLOCK_SIZE * (elem_idx + 1);
        if (row_offset < size) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    local_row[i * BLOCK_SIZE + j] = a[(offset + i) * size + row_offset + j];
                }
            }

            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    float sum = 0.0f;
                    for (k = 0; k < i; k++) {
                        sum += local_row[i * BLOCK_SIZE + k] * local_diag[k * BLOCK_SIZE + j];
                    }
                    local_row[i * BLOCK_SIZE + j] -= sum;
                    a[(offset + i) * size + row_offset + j] = local_row[i * BLOCK_SIZE + j];
                }
            }
        }
    } else {
        // Process column blocks (below diagonal)
        int col_offset = offset + BLOCK_SIZE * (elem_idx + 1);
        if (col_offset < size) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    local_col[i * BLOCK_SIZE + j] = a[col_offset + i * size + (offset + j)];
                }
            }

            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    float sum = 0.0f;
                    for (k = 0; k < j; k++) {
                        sum += local_diag[i * BLOCK_SIZE + k] * local_col[k * BLOCK_SIZE + j];
                    }
                    float diag_val = local_diag[j * BLOCK_SIZE + j];
                    local_col[i * BLOCK_SIZE + j] = (local_col[i * BLOCK_SIZE + j] - sum) / diag_val;
                    a[col_offset + i * size + (offset + j)] = local_col[i * BLOCK_SIZE + j];
                }
            }
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* local_row_block, 
                           __local float* local_col_block, int size, int offset) {
    int gx = get_global_id(0);
    int gy = get_global_id(1);
    int i, j, k;

    if (gx >= BLOCK_SIZE || gy >= BLOCK_SIZE) return;

    int block_row_idx = gx / BLOCK_SIZE;
    int block_col_idx = gy / BLOCK_SIZE;

    int row_offset = offset + BLOCK_SIZE * (block_row_idx + 1);
    int col_offset = offset + BLOCK_SIZE * (block_col_idx + 1);

    if (row_offset >= size || col_offset >= size) return;

    // Load row block
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            local_row_block[i * BLOCK_SIZE + j] = a[(offset + i) * size + col_offset + j];
        }
    }

    // Load column block
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            local_col_block[i * BLOCK_SIZE + j] = a[row_offset + i * size + (offset + j)];
        }
    }

    // Compute internal block update
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                sum += local_col_block[i * BLOCK_SIZE + k] * local_row_block[k * BLOCK_SIZE + j];
            }
            a[row_offset + i * size + col_offset + j] -= sum;
        }
    }
}
